contracts/DatasetRegistryTemplate.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract DatasetRegistryTemplate {
    struct Dataset {
        bytes32 dataHash;
        address issuer;
        uint256 createdAt;
        string uri;
    }

    address public owner;
    mapping(bytes32 => Dataset) private datasets;

    event DatasetRegistered(bytes32 indexed datasetId, bytes32 indexed dataHash, address indexed issuer, string uri, uint256 timestamp);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    constructor(address initialOwner) {
        require(initialOwner != address(0), "Invalid owner");
        owner = initialOwner;
    }

    function registerDataset(bytes32 datasetId, bytes32 dataHash, string calldata uri) external onlyOwner {
        require(datasets[datasetId].createdAt == 0, "Dataset exists");
        require(dataHash != bytes32(0), "Invalid hash");

        datasets[datasetId] = Dataset({
            dataHash: dataHash,
            issuer: msg.sender,
            createdAt: block.timestamp,
            uri: uri
        });

        emit DatasetRegistered(datasetId, dataHash, msg.sender, uri, block.timestamp);
    }

    function verifyDataset(bytes32 datasetId, bytes32 dataHash) external view returns (bool) {
        Dataset memory ds = datasets[datasetId];
        return ds.createdAt != 0 && ds.dataHash == dataHash;
    }
}

contracts/DocumentRegistryTemplate.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract DocumentRegistryTemplate {
    struct Document {
        bytes32 docHash;
        address issuer;
        uint256 issuedAt;
        string uri;
    }

    address public owner;
    mapping(bytes32 => Document) private documents;

    event DocumentRegistered(bytes32 indexed docId, bytes32 indexed docHash, address indexed issuer, string uri, uint256 timestamp);
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    constructor(address initialOwner) {
        require(initialOwner != address(0), "Invalid owner");
        owner = initialOwner;
    }

    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Invalid owner");
        address previousOwner = owner;
        owner = newOwner;
        emit OwnershipTransferred(previousOwner, newOwner);
    }

    function registerDocument(bytes32 docId, bytes32 docHash, string calldata uri) external onlyOwner {
        require(documents[docId].issuedAt == 0, "Document exists");
        require(docHash != bytes32(0), "Invalid hash");

        documents[docId] = Document({
            docHash: docHash,
            issuer: msg.sender,
            issuedAt: block.timestamp,
            uri: uri
        });

        emit DocumentRegistered(docId, docHash, msg.sender, uri, block.timestamp);
    }

    function verifyDocument(bytes32 docId, bytes32 docHash) external view returns (bool) {
        Document memory doc = documents[docId];
        return doc.issuedAt != 0 && doc.docHash == docHash;
    }
}

